const fs = require('fs');
const path = require('path');
const cp = require('child_process');

const cwd = process.cwd();
const packageJsonPath = path.join(cwd, 'package.json');
const packageLockPath = path.join(cwd, 'package-lock.json');

function run(command, args, options = {}) {
  const result = cp.spawnSync(command, args, {
    stdio: 'inherit',
    shell: process.platform === 'win32',
    ...options,
  });

  if (result.status !== 0) {
    process.exit(result.status || 1);
  }
}

function fileExists(file) {
  try {
    fs.accessSync(file);
    return true;
  } catch {
    return false;
  }
}

function readJson(file) {
  return JSON.parse(fs.readFileSync(file, 'utf8'));
}

function print(text = '') {
  process.stdout.write(String(text) + '\n');
}

function help() {
  print(`
PACKAGE-LOCK.JSON GUIDE

Why package-lock.json matters
- package-lock.json records the exact dependency tree resolved for the project.
- It ensures all environments install the same versions of direct and transitive dependencies.
- It improves reproducibility for local development, CI, staging, and production deployments.
- It allows npm ci to perform clean, deterministic installs.

Recommended team rules
1. Commit package-lock.json to version control.
2. Use npm ci in CI/CD and deployment pipelines.
3. Use npm install locally when intentionally changing dependencies.
4. Review package-lock.json changes in pull requests.
5. Keep Node.js and npm versions aligned across environments.
6. Never manually edit package-lock.json unless absolutely necessary.

Common workflows

A) First-time lock file generation
- Run: npm install
- This creates or updates package-lock.json based on package.json.

B) Clean reproducible install
- Run: npm ci
- npm ci requires package-lock.json and installs exactly what is locked.
- It removes node_modules first and fails if package.json and package-lock.json are out of sync.

C) Add a dependency
- Run: npm install <package> --save
- Commit both package.json and package-lock.json.

D) Add a dev dependency
- Run: npm install <package> --save-dev
- Commit both package.json and package-lock.json.

E) Update a dependency intentionally
- Run one of:
  npm install <package>@latest
  npm update
  npm audit fix
- Review resulting package-lock.json changes.
- Run tests.
- Commit package.json and package-lock.json if changed.

F) Refresh lock file without changing declared semver ranges
- Remove node_modules if needed.
- Run: npm install
- Commit package-lock.json if it changed.

CI/CD recommendations
- Use npm ci instead of npm install.
- Fail builds when package-lock.json is missing.
- Fail builds when package.json and package-lock.json are inconsistent.
- Cache npm cache directory if desired, but do not rely on node_modules reuse for correctness.
- Pin Node.js and npm versions in CI and production images.

Suggested deployment pipeline steps
1. Checkout source.
2. Verify package-lock.json exists.
3. Use the expected Node.js/npm version.
4. Run npm ci.
5. Run tests/build.
6. Deploy artifact.

Troubleshooting
- If npm ci fails due to lock mismatch:
  Run npm install locally, verify intended changes, and commit the updated lock file.
- If different environments resolve differently:
  Align Node.js and npm versions.
- If lock file churn is excessive:
  Standardize npm version and avoid unnecessary installs.

Commands supported by this script
--generate   Generate or refresh package-lock.json using npm install
--ci-check   Validate that package-lock.json exists and npm ci succeeds
--update     Update dependencies using npm update
--help       Show this guide
`);
}

function ensurePackageJson() {
  if (!fileExists(packageJsonPath)) {
    print('Error: package.json not found in current directory.');
    process.exit(1);
  }
}

function generateLockfile() {
  ensurePackageJson();
  print('Generating or refreshing package-lock.json with npm install...');
  run('npm', ['install']);
  if (fileExists(packageLockPath)) {
    print('package-lock.json generated/refreshed successfully.');
  } else {
    print('Warning: package-lock.json was not created.');
    process.exit(1);
  }
}

function ciCheck() {
  ensurePackageJson();

  if (!fileExists(packageLockPath)) {
    print('Error: package-lock.json is missing.');
    process.exit(1);
  }

  print('Running npm ci to validate reproducible install...');
  run('npm', ['ci']);
  print('npm ci completed successfully.');
}

function updateDependencies() {
  ensurePackageJson();

  if (!fileExists(packageLockPath)) {
    print('package-lock.json not found. Running npm install first...');
    run('npm', ['install']);
  }

  print('Updating dependencies with npm update...');
  run('npm', ['update']);

  print('Dependency update complete.');
  print('Next steps: review package-lock.json changes, run tests, and commit updates.');
}

function printSummary() {
  ensurePackageJson();

  const pkg = readJson(packageJsonPath);
  const hasLock = fileExists(packageLockPath);

  print('Project summary');
  print(`- package.json: present`);
  print(`- package-lock.json: ${hasLock ? 'present' : 'missing'}`);
  print(`- project name: ${pkg.name || '(unnamed)'}`);
  print(`- project version: ${pkg.version || '(unspecified)'}`);
  print('');
  print('Recommended next action:');
  print(hasLock ? '- Use npm ci in CI/CD for reproducible builds.' : '- Run with --generate to create package-lock.json.');
}

const arg = process.argv[2];

switch (arg) {
  case '--generate':
    generateLockfile();
    break;
  case '--ci-check':
    ciCheck();
    break;
  case '--update':
    updateDependencies();
    break;
  case '--help':
    help();
    break;
  case undefined:
    printSummary();
    print('');
    help();
    break;
  default:
    print(`Unknown argument: ${arg}`);
    print('Run with --help for usage.');
    process.exit(1);
}